<?php
/** Fuel log lifecycle and consumption analytics. */
declare(strict_types=1);require_once __DIR__.'/fuel_validation.php';function saveFuelLog(array $in,?int $id=null):array{$e=validateFuelInput($in);if($e)return[false,$e];$liters=(float)$in['quantity_liters'];$price=(float)$in['price_per_liter'];$data=['vehicle_id'=>(int)$in['vehicle_id'],'trip_id'=>!empty($in['trip_id'])?(int)$in['trip_id']:null,'fuel_station_id'=>!empty($in['fuel_station_id'])?(int)$in['fuel_station_id']:null,'fuel_type'=>$in['fuel_type'],'quantity_liters'=>$liters,'price_per_liter'=>$price,'cost'=>round($liters*$price,2),'odometer_reading'=>!empty($in['odometer_reading'])?(float)$in['odometer_reading']:null,'filled_by'=>trim((string)($in['filled_by']??''))?:null,'payment_method'=>trim((string)($in['payment_method']??''))?:null,'bill_number'=>trim((string)($in['bill_number']??''))?:null,'remarks'=>trim((string)($in['remarks']??''))?:null,'logged_date'=>$in['logged_date']];if($id){$set=[];foreach($data as $k=>$v)$set[]="$k=?";getDb()->prepare('UPDATE fuel_logs SET '.implode(',',$set).' WHERE id=?')->execute([...array_values($data),$id]);return[true,$id];}$data['uuid']=bin2hex(random_bytes(16));$data['fuel_code']='FUEL-'.date('Y').'-'.strtoupper(bin2hex(random_bytes(3)));$cols=array_keys($data);getDb()->prepare('INSERT INTO fuel_logs ('.implode(',',$cols).') VALUES ('.implode(',',array_fill(0,count($cols),'?')).')')->execute(array_values($data));$new=(int)getDb()->lastInsertId();logActivity('Fuel added','Fuel log #'.$new);getDb()->prepare('INSERT INTO notifications (user_id,title,message,priority) VALUES(NULL,?,?,?)')->execute(['Fuel added','Fuel recorded for vehicle #'.$data['vehicle_id'],'Normal']);return[true,$new];}
function fuelEfficiencyByVehicle():array{return getDb()->query('SELECT v.registration_number,COALESCE(SUM(t.actual_distance_km)/NULLIF(SUM(f.quantity_liters),0),0) efficiency,COALESCE(SUM(f.cost),0) fuel_cost FROM vehicles v LEFT JOIN trips t ON t.vehicle_id=v.id LEFT JOIN fuel_logs f ON f.vehicle_id=v.id GROUP BY v.id ORDER BY fuel_cost DESC')->fetchAll();}
